arguments.file_text:
@* Step indicator bar showing progress through the multi-step form *@

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var state = GetStepState(stepIndex);
            <li class="step-item text-center flex-fill @state" role="listitem">
                @if (state == "completed")
                {
                    <button class="btn btn-link p-0 text-decoration-none w-100"
                            @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block small mt-1 text-success fw-semibold">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(state == "active" ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">
                            @(stepIndex + 1)
                        </span>
                        <span class="step-label d-block small mt-1 @(state == "active" ? "fw-semibold text-primary" : "text-muted")">
                            @StepNames[stepIndex]
                        </span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public int HighestCompletedStep { get; set; }

    [Parameter]
    public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < HighestCompletedStep) return "completed";
        return "future";
    }
}

.step-indicator .step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
