+@page "/apply"
+@using sv_cd368222884246dfaa96e8e003552b53.Models
+@using sv_cd368222884246dfaa96e8e003552b53.Services
+@rendermode InteractiveServer
+@inject IApplicationService ApplicationService
+
+<PageTitle>Job Application</PageTitle>
+
+<div class="container py-4" style="max-width: 800px;">
+    <h2 class="text-center mb-4">Job Application</h2>
+
+    <StepIndicator CurrentStep="currentStep"
+                   HighestCompletedStep="highestCompletedStep"
+                   OnStepClicked="GoToStep" />
+
+    @switch (currentStep)
+    {
+        case 0:
+            <PersonalInfoStep Model="personalInfo"
+                              ValidateEmail="ApplicationService.ValidateEmailAsync"
+                              OnNext="NextStep" />
+            break;
+        case 1:
+            <WorkHistoryStep Entries="workEntries"
+                             OnNext="NextStep"
+                             OnBack="PreviousStep" />
+            break;
+        case 2:
+            <ReferencesStep References="references"
+                            OnNext="NextStep"
+                            OnBack="PreviousStep" />
+            break;
+        case 3:
+            <CoverLetterStep @bind-CoverLetter="coverLetter"
+                             OnNext="NextStep"
+                             OnBack="PreviousStep" />
+            break;
+        case 4:
+            <ReviewStep Personal="personalInfo"
+                        WorkEntries="workEntries"
+                        References="references"
+                        CoverLetter="coverLetter"
+                        IsSubmitted="isSubmitted"
+                        ApplicationId="applicationId"
+                        OnBack="PreviousStep"
+                        OnEditStep="GoToStep"
+                        OnSubmit="SubmitApplication" />
+            break;
+    }
+</div>
+
+@code {
+    private int currentStep;
+    private int highestCompletedStep;
+    private bool isSubmitted;
+    private int applicationId;
+
+    private PersonalInfoModel personalInfo = new();
+    private List<WorkEntryModel> workEntries = [new()];
+    private List<ReferenceModel> references = [new(), new()];
+    private string coverLetter = "";
+
+    private void NextStep()
+    {
+        if (currentStep < 4)
+        {
+            currentStep++;
+            if (currentStep > highestCompletedStep)
+                highestCompletedStep = currentStep;
+        }
+    }
+
+    private void PreviousStep()
+    {
+        if (currentStep > 0)
+            currentStep--;
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step < highestCompletedStep)
+            currentStep = step;
+    }
+
+    private async Task SubmitApplication()
+    {
+        var application = new JobApplication(
+            personalInfo.ToRecord(),
+            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
+            references.Select(r => r.ToRecord()).ToList(),
+            coverLetter
+        );
+
+        applicationId = await ApplicationService.SubmitApplicationAsync(application);
+        isSubmitted = true;
+    }
+}
+

